def select_next_node(cur_truck_pos, depot_pos, all_truck_pos, unvisited_customers, current_time, truck_speed, time_windows):
    # {Design an algorithm that uses a weighted score evaluating time window adherence, travel distance, and distribution of trucks to select the next node.}

    def travel_time(pos1, pos2):
        return np.linalg.norm(pos1 - pos2) / truck_speed

    best_score = float('inf')
    best_node = None

    for i, customer in enumerate(unvisited_customers):
        earliest, latest = time_windows[i]
        travel_to_customer = travel_time(cur_truck_pos, customer)
        arrival_time = current_time + travel_to_customer

        # Penalty if arriving too early, incentivizes waiting, if necessary
        if arrival_time < earliest:
            penalty = earliest - arrival_time
        else:
            penalty = 0

        # Large penalty if time window is missed entirely
        if arrival_time > latest:
            penalty += (arrival_time - latest) * 10

        # Calculate a score incorporating penalties and travel time
        score = travel_to_customer + penalty

        # Check distribution of other trucks to prioritize less clustered customers
        for other_truck in all_truck_pos:
            distribution_penalty = np.linalg.norm(customer - other_truck) * 0.1
            score += distribution_penalty

        if score < best_score:
            best_score = score
            best_node = i

    return best_node

